/**
 * Ala Dapoer Adem - Minified JS - Production
 */
document.addEventListener('DOMContentLoaded',function(){initScrollToTop();initFeedbackForm();initSmoothScroll();initNavbarTransition()});function initScrollToTop(){const e=document.getElementById('scrollTopBtn');if(!e)return;window.addEventListener('scroll',function(){window.pageYOffset>300?e.style.display='block':e.style.display='none'});e.addEventListener('click',function(){window.scrollTo({top:0,behavior:'smooth'})})}function initFeedbackForm(){const e=document.getElementById('feedbackForm');if(!e)return;e.addEventListener('submit',function(t){t.preventDefault();const s=new FormData(this),n=s.get('name'),a=s.get('message');if(!n||!a)return void showAlert('Mohon isi semua field!','warning');console.log('Feedback submitted:',{name:n,message:a}),showAlert('Terima kasih! Saran & masukan Anda telah diterima.','success'),this.reset()})}function initSmoothScroll(){document.querySelectorAll('a[href^="#"]').forEach(e=>{e.addEventListener('click',function(t){const s=this.getAttribute('href');if('#'===s)return;const n=document.querySelector(s);n&&(t.preventDefault(),n.scrollIntoView({behavior:'smooth'}))})})}function initNavbarTransition(){const e=document.querySelector('.navbar');if(!e)return;window.addEventListener('scroll',function(){window.scrollY>50?e.classList.add('scrolled'):e.classList.remove('scrolled')})}function showAlert(e,t='info'){const s=document.createElement('div');s.className=`alert alert-${t} alert-dismissible fade show position-fixed`,s.style.cssText='top: 80px; right: 20px; z-index: 9999; min-width: 300px;',s.innerHTML=`${e}<button type="button" class="btn-close" data-bs-dismiss="alert"></button>`,document.body.appendChild(s),setTimeout(()=>{s.remove()},5e3)}function initScrollAnimations(){const e=new IntersectionObserver(t=>{t.forEach(t=>{t.isIntersecting&&t.target.classList.add('fade-in')})},{threshold:.1});document.querySelectorAll('.fade-in').forEach(t=>{e.observe(t)})}function searchRecipes(e){const t=document.querySelectorAll('.recipe-card'),s=e.toLowerCase();t.forEach(e=>{const n=e.querySelector('.recipe-link').textContent.toLowerCase();n.includes(s)?e.style.display='block':e.style.display='none'})}function initImageLazyLoad(){const e=document.querySelectorAll('img[data-src]'),t=new IntersectionObserver(s=>{s.forEach(s=>{if(s.isIntersecting){const n=s.target;n.src=n.dataset.src,n.removeAttribute('data-src'),t.unobserve(n)}})});e.forEach(e=>t.observe(e))}window.AlaDapoerAdem={showAlert,searchRecipes};
